var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"대략적인 줄거리는 이미 파악하고 있습니다.","JPN":"話の大筋はすでに把握済みです。","ENG":"I am already aware of the general plot.","TWN":"大概的情節我已經明白了。"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"프리드웬의 기관장께서는 꽤 일찍부터 저희에게 파편에 대한 조사를 요청하셨거든요.","JPN":"プリドウェンの機関長は、以前から私たちに破片の調査を要請していました。","ENG":"We were requested to conduct an investigation on the Fragment by Prydwen's chief a while ago.","TWN":"普利多溫的機關長很早就請求我們對碎片進行了調查。"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서? 성과가 좀 있었어?","JPN":"で？　成果はあったのか？","ENG":"So? Any progress?","TWN":"然後呢？有什麼成果嗎？"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아니요. 그다지 유의미한 성과는 없었습니다.","JPN":"いいえ。あまり意味のある成果はありませんでした。","ENG":"No. There were not any significant results.","TWN":"沒有，並沒有多少有意義的成果。"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"국토 면적이 작다고 해도, 성황청은 엄연히 권력과 위계가 존재하는 독립국가입니다.","JPN":"国土の面積が狭いとはいえ、聖皇庁は厳として権力と位階が存在する独立国家です。","ENG":"Although the size is small, the Holy Curia is still an independent nation where authority and hierarchy exist.","TWN":"雖然國土面積小，但聖皇廳卻也是存在權力和權威的獨立國家。"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"겨우 집행사제의 권한으로 접근할 수 있는 정보는 한정되어 있죠.","JPN":"たかが執行司祭の権限では、得られる情報が限られています。","ENG":"There is a limit to the information that an Inquisitorial Priest has access to.","TWN":"僅憑執行祭司的許可權能獲取的情報有限。"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"더욱이 그 정보가 <color=#ffd34c>성배</color>와 관련된 것이라면.","JPN":"その情報が<color=#ffd34c>聖杯</color>に関するものとなれば、尚更です。","ENG":"And, if that information has to do with the <color=#ffd34c>Holy Grail</color>,","TWN":"而且，如果該情報與<color=#ffd34c>聖杯</color>有關……"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기관과 연결고리인 저에게 성황청은 관련 정보를 넘기려 하지 않을 겁니다.","JPN":"機関と繋がりのある私に、聖皇庁は関連情報を渡そうとしないはずです。","ENG":"the Holy Curia will hold relevant information from me since I'm the link to the Institution.","TWN":"聖皇廳就更不會將相關情報交給與機關有關聯的我。"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"쳇, 하여간 어딜가나 그 놈의 기싸움이 문제라니깐.","JPN":"チッ、いつもそことの睨み合いが邪魔するんだよ。","ENG":"Tsk. It's always a power struggle, isn't it?","TWN":"嘖，怎麼不管到哪裡都要搞這種意氣之爭……"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"다만…….","JPN":"ただ……","ENG":"However...","TWN":"只是……"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"다만?","JPN":"ただ？","ENG":"However?","TWN":"只是？"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기적심의회의 전 의장이셨던 요한 니콜라이 3세께서는 버넷 경과 막역한 사이셨습니다.","JPN":"奇跡審議会の元議長であったヨハン・ニコライ3世は、バーネット卿と大変親しい間柄でした。","ENG":"The former chairman of the Miracle Investigation Council, Johan Nicholas III, was close to Sir Burnett.","TWN":"奇蹟議會前議長約翰·尼古拉3世與伯內特卿是莫逆之交。"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"다시 말해, 성황청 내부에서 파편을 두고 버넷 경과 고고학부장이 갈등을 빚었다면.","JPN":"つまり、聖皇庁の内部で破片をめぐってバーネット卿と考古学部長が対立していたとしたら……","ENG":"In other words, if Sir Burnett and the Dean of Archeology had conflict over the Fragment within the Holy Curia,","TWN":"換句話說，如果是就聖皇廳領土內的碎片問題，伯內特卿和考古學教授產生了矛盾的話。"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"십중팔구……. 추기경께서 버넷 경을 지원하셨을 것이라는 맥락을 읽을 수 있겠죠.","JPN":"十中八九……枢機卿はバーネット卿を支持していたでしょう。","ENG":"we can assume the context... that Cardinal Johan would've supported Sir Burnett.","TWN":"十之八九……伯內特卿會得到樞機主教的支持。"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇구나!","JPN":"そうか！","ENG":"Okay!","TWN":"原來如此！"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼, 그 추기경 할배한테 가서 사건에 대해서 물어보면 되겠네!","JPN":"じゃあ、その枢機卿のジジイのところに行って、事件について聞いてみればいいんだ！","ENG":"Then, we should go ask that old Cardinal guy about the incident!","TWN":"那麼，可以去問問那個樞機主教老頭關於案件的事了！"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기꺼이 정정해 드리죠.","JPN":"喜んで訂正いたします。","ENG":"I would be more than happy to rephrase.","TWN":"請容我糾正一下。\xA0"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"예하께서는 지난 불미스러운 사건으로 인해 운명을 달리하셨습니다.","JPN":"猊下は、芳しくない事件によりお亡くなりになりました。","ENG":"His Eminence passed away during the distressing incident in the past.","TWN":"主教因為上次的醜聞，已經離開了人世。"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"저런. 고인의 명복을 빌겠네.","JPN":"おっと。それはご冥福をお祈りする。","ENG":"Ahh. May he rest in peace.","TWN":"哎呀，願故人安息。"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"쯧, 그럼 단서는 여기서 끊어진 건가?","JPN":"チッ、じゃあ手がかりはここで終わりなのか？","ENG":"Tsk. Is this where the trail ends, then?","TWN":"嘖，那線索就這麼斷了？"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L39_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"같은 맥락에서 기관 분들께서 봐주셨으면 하는 것이 있습니다.","JPN":"実はその繋がりで、機関のみなさんに見ていただきたいものがあります。","ENG":"There is something I would like you to see, in that context.","TWN":"出於同樣的原因，希望機關的各位能幫我看一下。"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"예하의 유품을 정리하면서, 저로서는 이해할 수 없는 문서가 있었거든요.","JPN":"猊下の遺品を整理している途中、私には到底、理解できない文書を見つけたのです。","ENG":"I found an incomprehensible document while I was organizing His Eminence's belongings.","TWN":"在整理主教遺物的時候，我找到了一份令我無法理解的文件。"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"문서라고?","JPN":"文書だと？","ENG":"A document?","TWN":"文件？"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"열람을 도와드리겠습니다. 자리를 옮기시죠.","JPN":"見ていただけるようでしたら、場所を移しましょう。","ENG":"I will provide access to it. Let us move somewhere else.","TWN":"我給你們看一下，請跟我來。"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이건, <color=#ffd34c>차원함선 렌탈 계약서</color>……?","JPN":"これは、<color=#ffd34c>次元艦船レンタル契約書</color>……？","ENG":"This is a <color=#ffd34c>dimensional ship rental contract</color>...?","TWN":"這是，<color=#ffd34c>次元戰艦租賃契約</color>……？"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"말씀하신대로 생전 예하께서 차원함선을 대여해주는 업체들과 맺은 계약서입니다.","JPN":"そのとおり、生前の猊下が次元艦船を貸与している複数の会社と交わした契約書です。","ENG":"It is, as you said, contracts with companies that provide rental dimensional ships that His Eminence signed back when he was still alive.","TWN":"正如你所說，這是主教生前與租賃次元戰艦的企業簽訂的契約。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"매달 3~4회 씩, 여러 업체를 바꿔가면서, 대략 15년 치 분량입니다.","JPN":"毎月3～4回、契約対象を変えながら、およそ15年分の資料が残っていますです。","ENG":"It is approximately 15 years' worth of contracts, with three to four rentals a month, signed with different companies.","TWN":"每個月3、4次，換了好幾家企業，大概是15年的分量。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"15년 치? 수상할 정도로 많군.","JPN":"15年分？　怪しいほど多いな。","ENG":"15 years? That's a suspiciously long amount of time.","TWN":"15年的量？確實是多到令人感到可疑。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 중, 가장 최근 날짜는…… 2년 전.","JPN":"そのうち、もっとも最近の日付は……2年前。","ENG":"And the most recent date is... from 2 years ago.","TWN":"其中，最近的日期是……2年前。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잠깐, 2년 전이라면……?","JPN":"待て、2年前って……？","ENG":"Wait, 2 years ago...?","TWN":"等一下，2年前的話……？"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"캡틴 렌탈, 디멘션 렌탈 쉽, 플라티나 캐피탈…….","JPN":"キャプテン・レンタル、ディメンション・レンタル・シップ、プラチナ・キャピタル……","ENG":"Captain Rental, Dimension Rental Ship, Platina Capital...","TWN":"隊長租賃，次元租賃，白金運通資本……"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하나같이 삼류 업체에다가…… 퇴역 함선 주제에 이상할 정도로 가격도 비싸군.","JPN":"どこも三流会社で……退役艦船のわりには、値段が高すぎる。","ENG":"They're all C-list companies, and... suspiciously expensive for ships out of commission.","TWN":"都是三流企業……而且都是退役艦船，價格卻貴的離譜。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"정상적인 성무 수행이라면, 성황청으로부터 함선을 지원받을 수 있었을 거야.","JPN":"通常の聖務の遂行なら、聖皇庁から艦船を支援してもらえたはずだ。","ENG":"If it were for an ordinary sacred mission, the Holy Curia could've provided him with a ship.","TWN":"如果是正常執行聖務，那應該可以得到聖皇廳的艦船支援才對。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"즉, 추기경께서는 성황청의 이름이 밖으로 드러나지 않기를 바라셨던 건가?","JPN":"つまり、枢機卿は聖皇庁の名が表に出ることをお望みではなかったということか？","ENG":"So, does that mean the Cardinal didn't want the Holy Curia's name to be exposed?","TWN":"也就是說，樞機主教不希望使用聖皇廳的名義？"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"소문대로 예리하시군요.","JPN":"噂どおり、鋭いですね。","ENG":"You are sharp, like I heard you are.","TWN":"如傳聞所言，很敏銳的觀察力。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"여기 있는 이 계약서의 기재 사항은 전부 엉망일뿐더러, 경비 처리도 되어있지 않아요.","JPN":"ここにある契約書の記載事項はすべてデタラメである上、経費処理もされていません。","ENG":"The information filled out in these contracts is all nonsense, and it has not been filed as expenses either.","TWN":"這份契約裡記載的所有內容都是亂七八糟的，而且經費也沒有處理好。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"다시 말해, 예하께서는 <color=#ffd34c>어떤 사적인 이유</color>로 지난 15년 간, 함선을 대여해왔다는 뜻이죠.","JPN":"つまり、猊下は<color=#ffd34c>ある私的な理由</color>で15年間、艦船を貸与してきたということです。","ENG":"Which means that His Eminence had <color=#ffd34c>some kind of personal reason</color> for renting ships for the past 15 years.","TWN":"也就是說，主教在過去的15年裡，一直以某種<color=#ffd34c>私人原因</color>租借了艦船。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이건…… 지금까지 제가 알고 있던 예하의 성품과는 전혀 다른 행동입니다.","JPN":"これは……私の知る猊下のお姿からは、想像できない内容です。","ENG":"And... that is unlike His Eminence's character that I know.","TWN":"這個行為……完全不符合我之前所知的主教品行。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 그래서 결론이 뭐야?","JPN":"ったく。それで、結論はなんだよ？","ENG":"Blimey. So, what are you trying to say?","TWN":"真是的，所以你的結論是什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그쪽 요원 분께서는 성격이 급하시군요.","JPN":"そちらのエージェントさんは、せっかちですね。","ENG":"Quite the impatient agent, you are.","TWN":"看來這位特工的性格很急。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아직 결론을 내기는 이릅니다.","JPN":"まだ結論を出すのは早いです。","ENG":"It is too early to draw conclusions.","TWN":"現在下結論還為時過早。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이상한 부분은 또 있습니다. 이상할 정도로 대여 목적만큼은 다 똑같거든요.","JPN":"疑わしいところはまだあります。貸与の目的の項目が、全て同じなのです。","ENG":"There is another odd thing about this. Strangely enough, the purpose of renting is all the same.","TWN":"因為，還有奇怪的部分。那就是每次租賃的目的都一樣，令人不得不生疑。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"대여 목적?","JPN":"貸与の目的？","ENG":"Purpose of renting?","TWN":"租賃目的？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어차피 기재 사항은 전부 엉망이라고…….","JPN":"さっき記載事項は全部デタラメって……","ENG":"Didn't you say the information filled out was all nonsense–","TWN":"不是說記載的內容都亂七八糟……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잠깐, 대여 목적이 <color=#ffd34c>낚시</color>라고……?","JPN":"はあっ！？　貸与目的が<color=#ffd34c>釣り</color>だと……？","ENG":"Wait. Purpose of renting is <color=#ffd34c>fishing</color>...?","TWN":"等一下，租賃目的是<color=#ffd34c>釣魚</color>……？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하하하하하하핫! 그런 거였나!","JPN":"ハハハハハハハハッ！　そういうことだったのか！","ENG":"Hah hah hah hah hah! I see!","TWN":"哈哈哈哈哈哈！原來如此啊！"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"은퇴한 뒤로는 소탈한 삶을 사시는 줄 알고 있었는데, 형님께 또 한 방 먹었구만!","JPN":"引退後は質素に暮らしていると思っていたが、また一発食わされたな！","ENG":"I thought he lived an easy-going life after retiring, but I guess Sir Burnett fooled me again!","TWN":"還以為退休以後過著瀟灑的生活，沒想到又被大哥擺了一道。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"역시…….","JPN":"やはり……","ENG":"I knew it...","TWN":"果然……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기관 분들께 이걸 보여드리면 뭔가 짐작하시는 바가 있으리라 생각했습니다.","JPN":"機関の人にこれを見せれば、何か手掛かりを掴めると思っていました。","ENG":"I thought you would know something if I showed you this.","TWN":"我就知道給機關的人看這些東西，應該就能猜到些什麼。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그래. 대충 형님 행동이 짐작 가는군.","JPN":"ああ。どういうことなのか、大体の見当はついた。","ENG":"Yeah. I can imagine what he did.","TWN":"是啊，我大概能猜到大哥的行動。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"제임스의 증언대로 아마 형님께서는 과거 성황청의 파편을 두고 그와 결전을 벌였겠지.","JPN":"ジェームスの証言どおり、バーネットは過去に聖皇庁の破片を巡り彼と勝負しただろう？","ENG":"Like James' testimony, Sir Burnett probably fought with him for the Holy Curia's Fragment.","TWN":"正如詹姆斯所說，大哥過去曾為位於聖皇廳的碎片與他展開了決戰。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"임무는 실패하고 파편의 행방은 알 수 없게 되었지만, 형님은 포기하지 않으셨어.","JPN":"任務は失敗し、破片の行方はわからなくなったが、バーネットは諦めていなかった。","ENG":"After the mission failed, the Fragment was lost, but he didn't give up.","TWN":"雖然任務失敗了，碎片下落不明，但是大哥沒有放棄。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"은퇴 후에 우리가 눈치채지 못하도록, 성황청 협력자와 함께 파편 탐색을 계속하고 있었던 거야.","JPN":"引退後、俺たちに気付かれないよう、聖皇庁の協力者とともに引き続き破片の探索をしていたのだ。","ENG":"After retiring, he sneakily had someone inside the Holy Curia to help him continue his search for the Fragment.","TWN":"退休後在不讓我們察覺到的情況下，與聖皇廳內部的合作者一起不斷探索碎片。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"15년 동안 이면세계를 뒤져가면서 말이지.","JPN":"15年間、裏世界を回りながら。","ENG":"Searching up and down the Counterside for 15 years.","TWN":"15年來，應該翻遍了異界。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그렇군요.","JPN":"なるほど。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어쩌면 두 분께서 찾고 계셨던 건, 정말로 <color=#ffd34c>성배</color>였을지도 모르겠습니다.","JPN":"もしかしたらお二人が探していたのは、本当に<color=#ffd34c>聖杯</color>だったのかもしれません。","ENG":"Perhaps it was truly the <color=#ffd34c>Holy Grail</color> that the two were searching for.","TWN":"或許那二位在尋找的，真的就是<color=#ffd34c>聖杯</color>。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"그래, 네 말이 맞다. 로이.","JPN":"ああ、お前の言うとおりだ。ロイ。","ENG":"You're right. Roy.","TWN":"沒錯，你說的對。"},"stage":{"bg":"FALL_PARK","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"어떤 대의명분을 댄다 해도, 내가 너희 가족을 신경 쓰지 못한 건 사실이야.","JPN":"どんな大義名分も言い訳にならない。俺がお前の家族を見過ごしてきたのは事実だ。","ENG":"I can say it was for a noble cause, but it's still true that I wasn't able to take care of your family.","TWN":"雖然我有資格，我卻沒有關心你們一家人。"},"stage":{"bg":"FALL_PARK","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"이제 와서…… 그 깊은 감정의 골을 해결하는 건 불가능하겠지.","JPN":"今更……その深い心の溝を埋めることは不可能だろう。","ENG":"And... it would be impossible to fill that deep of an emotional void now.","TWN":"事到如今……才來解決那早已破裂的感情是不可能的。"},"stage":{"bg":"FALL_PARK","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그 대의명분이라는 게…… 이런 거였어, 할배?","JPN":"その大義名分って……これのことだったのか？　ジジイ。","ENG":"Is this... the noble cause you were talking about, Gramps?","TWN":"你說的資格……就是這個嗎，爺爺？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 역시 맥락이 맞지 않는 부분이 있습니다.","JPN":"ですが、やはり筋が合わないところがあります。","ENG":"But there is one part that does not fit in with the context.","TWN":"但是還是有一些不對的地方。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성배와 관련된 사안이니 예하께서는 최대한 그걸 감추려해도 이해할 수 있습니다만.","JPN":"聖杯に関わった事案ですので、猊下がそれを隠そうとするのは理解できますが……","ENG":"As it was related to the Holy Grail, I can understand why His Eminence would try to hide it as best he could.","TWN":"既然事關聖杯，主教會想盡辦法掩蓋，倒是可以理解。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"버넷 경께서는 어째서 파편 탐색에 관해 기관에 알리지 않았던 걸까요?","JPN":"バーネット卿はどうして破片の探索について、機関に知らせなかったのでしょうか。","ENG":"However, why did Sir Burnett not inform the Institution about the search for the Fragment?","TWN":"但伯內特卿為什麼沒有告訴機關有關搜尋碎片的事？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그것이 진짜 성배든 아니면 파편이든 기관에게 있어서는 중요한 문제였을 텐데요.","JPN":"それが本物の聖杯であろうが、もしくは破片であろうが、機関にとっては重要な問題だったはずです。","ENG":"It would have been a significant issue for the Institution, whether it was the real Holy Grail or a Fragment.","TWN":"不管是真正的聖杯還是碎片，對機關來說都是重要問題。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그건 그렇군…….","JPN":"それもそうだな……","ENG":"You're right…","TWN":"那倒是……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"루체 집행사제님! 큰 일입니다!","JPN":"ルーチェ執行司祭様！　大変です！","ENG":"Ms. Luce! Something came up!","TWN":"露契執行祭司！不得了了！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L11_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"성황청 내부에서 학회 녀석들의 움직임이 포착되었습니다!","JPN":"聖皇庁の内部で、学会のやつらの動きを捉えました！","ENG":"We detected some Society bastards move within the Holy Curia!","TWN":"在聖皇廳內部捕捉到了學會那群傢伙的動向！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"알겠습니다. 곧 준비하죠.","JPN":"わかりました。すぐ準備します。","ENG":"Very well. I will be there shortly.","TWN":"知道了，馬上準備吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"우리도 서두르자고, 모건 할배!","JPN":"俺たちも急ごう、モーガンのジジイ！","ENG":"We gotta hurry too, Morgan!","TWN":"我們也抓緊時間吧，老頭！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"교수는 파편의 행방을 알고 있다고 했어.","JPN":"教授は破片の行方を知ってるって言ってた。","ENG":"The Professor said he knew where the Fragment was.","TWN":"教授說他知道碎片的下落。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까 그 자식만 잡아서 족치면 그 성배가 뭔지도 알게 되겠지.","JPN":"だからあいつさえ捕まえて叩けば、その聖杯が何なのかもわかるはずだ。","ENG":"So, if we find him and beat him up, we'll figure out what the Holy Grail is too.","TWN":"所以只要抓到那個傢伙，就能知道聖杯到底是什麼了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"알겠네, 가지.","JPN":"わかった、行こう。","ENG":"All right. Let's go.","TWN":"知道了，走吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"학부장님, 대체 뭘 찾으시는 겁니까?","JPN":"学部長、いったい何をお探しなのですか？","ENG":"What are you looking for, sir?","TWN":"院長，你到底在找什麼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그곳에 다다르기 위해 필요한 물건이지.","JPN":"あそこに辿り着くために必要な物だ。","ENG":"The thing that's required to reach the place.","TWN":"是一個為了到達那裡而需要的東西。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"공항에서 기관 녀석들에 붙잡히기 직전에…….","JPN":"空港で機関のやつらに捕まる直前……","ENG":"I asked a trustworthy underling...","TWN":"在機場被機關的那些傢伙堵住之前……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"믿을 만한 부하에게 시켜서…… 미리 약속한 장소로 가져다 놓으라고 부탁했다네.","JPN":"信用できる部下に……あらかじめ約束した場所に持って行くようにと頼んだのだ。","ENG":"right before getting caught at the airport by the Institution bastards... to put it at the predetermined place.","TWN":"我便已經指使可靠的部下……讓他提前把東西送到約好的地方。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"녀석이 허튼 마음을 품지 않았다면, 분명 이곳에 있을 거야.","JPN":"やつに変な意図がないのなら、きっとここにあるはずだ。","ENG":"It should be here if he wasn't foolish.","TWN":"如果他沒有異心，那東西肯定在這裡。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그렇지…… 역시 여기 있군.","JPN":"よし……やはりここだったか。","ENG":"Yes... Here it is.","TWN":"沒錯……果然在這裡。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"그 케이스는……?","JPN":"そのケースは……？","ENG":"That case is...","TWN":"那個箱子是……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ffd34c>오보에</color>로군요. 엘리시움의 그림자를 종으로 부리실 생각이십니까?","JPN":"<color=#ffd34c>オーボエ</color>ですね。エリシウムのシャドウを使役するつもりですか？","ENG":"It's an <color=#ffd34c>oboe</color>. Are you attempting to use a Shadow of Elysium as a servant?","TWN":"原來是<color=#ffd34c>雙簧管</color>。你是想把愛樂組織的暗影當作奴僕使喚嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그림자? 틀렸네.","JPN":"シャドウ？　違う。","ENG":"Shadow? No.","TWN":"暗影？錯了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"이런 상황에서 통제도 못하는 그림자 하나가 무슨 쓸모가 있겠나?","JPN":"この状況で統制できないシャドウ一匹、なんの役にも立たんだろう。","ENG":"What good would an uncontrollable Shadow be in this kind of situation?","TWN":"在這種情況下，無法控制的暗影又有什麼用呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"그럼……?","JPN":"では……？","ENG":"Then...?","TWN":"那……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"엘리시움의 그림자들에게 있어서 악기는 힘의 원천과 같은 물건이지만…….","JPN":"エリシウムのシャドウたちにとって、楽器は力の源も同様だが……","ENG":"To the Shadows of Elysium, instruments are like the source of their power...","TWN":"對愛樂組織的暗影來說，樂器如同力量的源泉……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"},"R":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"동시에 이 악기들은 그 자체가 각기 다른 선율, 개성을 가진 아티팩트이기도 하다네.","JPN":"それと同時にこの楽器はそれ自体が各々違う旋律、個性を持つアーティファクトでもある。","ENG":"But at the same time, these are Artifacts that possess unique melodies and traits.","TWN":"同時，這些樂器本身也是具有不同旋律和個性的人造神器。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그들을 통솔하는 존재가 각각의 선율을 통제하고 공명시킬 수 있다면.","JPN":"彼らを統率する存在が、各々の旋律を統制し共鳴させることができれば……","ENG":"If an entity that commands them can control each of those melodies to create resonance,","TWN":"如果統領她們的存在能夠控制和共鳴各自的旋律。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"차원 계면을 완전히 융해시켜 버릴 정도로 막대한 차원 균열을 발생시킬 수도 있겠지.","JPN":"次元界面を完全に融解させるくらい、莫大な次元亀裂を発生させることもできるだろう。","ENG":"it should be possible to create a dimensional rift vast enough to melt the dimension surface.","TWN":"次元可能會產生巨大的次元裂縫，足以使邊界完全融化。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"그럼, 다른 악기들도 필요한 것 아닙니까?","JPN":"となると、他の楽器も必要なのでは？","ENG":"Then, wouldn't you need more instruments to do that?","TWN":"那麼，還需要其他樂器嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그렇지는 않네. 한 두사람이 통과할 만한 작은 균열이라면 악기 하나 정도면 충분해.","JPN":"いいや。1、2人程度が通過できる小さな亀裂なら、一つで十分だ。","ENG":"Not exactly. One instrument is acceptable to create a rift small enough for one or two people to pass.","TWN":"不，如果是個只能通過一、二個人的小裂縫，那麼一個樂器便足夠了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"문제는…….","JPN":"問題は……","ENG":"The issue is...","TWN":"問題是……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"원하는 차원에 도달할 수 있는 방법. 그리고 그걸 성공시킬 운이겠지.","JPN":"望んだ次元に到達できる方法。そして、それを成功させる運だろうな。","ENG":"how to reach the dimension you want, and the luck to make that happen.","TWN":"到達所去次元的方法，和使其成功的運氣。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"도달이라고요……?","JPN":"到達……？","ENG":"Reach a dimension...?","TWN":"到達……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"설마 차원 균열에 맨몸으로 뛰어드시겠다는 말씀입니까!?","JPN":"まさか、次元亀裂に何の装備もなく飛び込むつもりですか？","ENG":"Are you saying you'd just jump into a dimensional rift yourself?","TWN":"難道你想要毫無防備地跳進次元裂縫中去？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"너무 위험합니다! 지금 학부장님의 몸 상태라면 위상차를 견디지 못할 겁니다.","JPN":"あまりにも危険です！　今の学部長のお体では、位相の差に耐えられません。","ENG":"That's too dangerous! Your current body state wouldn't be able to withstand the phase difference.","TWN":"太危險了！以你現在的身體狀況，恐怕是承受不了能量差的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"차라리 함선을 수배하시죠!","JPN":"いっそ艦船を手配してください！","ENG":"Why don't you just look for a ship?!","TWN":"乾脆使用艦船吧！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"자네는 하나만 알고 둘은 모르는군.","JPN":"君は何もわかっていない。","ENG":"You are very nearsighted.","TWN":"你只知其一，不知其二。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"우리는 지금 쫓기고 있는 상황이야. 이런 상황에서 우리가 탈만한 함선이 나타난다면.","JPN":"私たちは今追われている身だ。この状況で艦船が手配できたら……","ENG":"We are being chased. And if a dimensional ship big enough to carry us appears,","TWN":"我們現在正處於被追趕的狀況。在這種情況下，如果出現我們能乘坐的艦船……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"오히려 그것이야말로 필히 기관이 파둔 함정일 거야.","JPN":"それは機関の罠だろうな。","ENG":"that would most likely be a trap set by the Institution.","TWN":"那反倒才是機關設下的陷阱。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_QM","text":{"KOREA":"어라? 그럼 고고학부장님이 순순히 악기를 얻게 된 건, 누가 판 함정이었을까?","JPN":"あれ？　じゃあ、考古学部長があっさり楽器を手に入れられたのは、誰の罠なんだろうね？","ENG":"Huh? Then who set the trap to help you get the instrument so easily?","TWN":"咦？那麼考古學教授能順利獲得樂器，又是誰設的陷阱呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_QM","text":{"KOREA":"뿌슝빠슝♬","JPN":"バッキューン♬","ENG":"Pew pew♬","TWN":"咻砰咻砰♬"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L29_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"크헉……!?","JPN":"くはっ……！？","ENG":"Krrgh...?!","TWN":"呃……？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"이, 이, 이 말뚝은 설마……!?","JPN":"こ、こ、この杭はまさか……！？","ENG":"Th-th-this stake is....?!","TWN":"這，這，這鐵釘難道是……？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"아하하핫! 그게 누구겠어? 학회의 귀염둥이 토끼, 리벳 님이지!","JPN":"あはははっ！　誰って、学会の可愛いウサギちゃん、リベット様だよ！","ENG":"Ah ha ha hah! Who do you think it is? It's Rivet, the adorable bunny of the Society!","TWN":"哈哈哈！還能是誰？當然是學會的可愛兔子，里維啦！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"요즘 학회가 너~ 무 평화로워서 총 쏠 일이 없었는데 말이야.","JPN":"最近学会が平和すぎて、銃を撃つ機会がなかったんだよね。","ENG":"The Society was sooo peaceful that I didn't have a chance to shoot recently.","TWN":"最近學會太～平靜了，所以都沒機會開槍。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"고고학부장님께서 이렇게 탈옥해 주셔서 너무~ 너무~ 고마운 거 있지?","JPN":"考古学部長がこうやって脱獄してくれて、本っ当にありがとう！","ENG":"I'm so, sooo grateful to you for breaking out, Dean of Archeology!","TWN":"但考古學教授會這樣越獄，真的太～讓我感謝了？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그러니까 고마운 만큼 마구 쏴줄 게!","JPN":"だから、お礼にいっぱい撃ってあげるね！","ENG":"So, as a token of my appreciation, I'll shoot down them all!","TWN":"所以，我有多感激，就射多少吧！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"거스름돈은 필요없다구!","JPN":"釣りはいらないよ！","ENG":"No need to refuse!","TWN":"不用找零喔！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"학부장님, 피하십시오! 학회장이 부리는 미치광이입니다!","JPN":"学部長、お逃げください！　学会長のところのいかれた娘です！","ENG":"Be careful, sir! It's the lunatic who's under the President!","TWN":"院長，請躲開！是學會長手下的瘋子！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"리벳이로군.","JPN":"リベットだな。","ENG":"Rivet.","TWN":"原來是里維。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"상황을 보아하니 맥크레디 양이 시킨 건가?","JPN":"状況を見るに、マクレディー君なのか？","ENG":"It seems like Ms. MacCready wanted you to do this.","TWN":"看樣子是麥克蕾蒂小姐指使的。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"옹야! 쓸데없이 기관을 자극했다나 뭐라나? 아무튼 고고학부장을 데려오라고 했거든!","JPN":"そう！　なんでも機関を刺激したんでしょ？　とにかく、考古学部長を連れて来いってさ！","ENG":"Yessir! She said something about you needlessly provoking the Institution or something. Anyway! She wanted me to bring you!","TWN":"哎呀！她說你沒事惹機關做什麼，反正就是要我把考古學教授給找回來！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"살려서 데려오라는 말은 없었으니까, 쇠꼬챙이 한두 개 정도는 괜찮지 않겠어?","JPN":"生きたまま連れて来いとは言われてないから、金属ドリルを1、2回食らわせても問題ないでしょ？","ENG":"She never said you had to be alive, so a few skewers should be fine, right?","TWN":"也沒說要不要留你活口，所以釘上一二個鐵釘應該沒問題吧？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"어머니의 보살핌 아래에 우리는 곧 하나가 될 지니.","JPN":"母の腕の中で、我々はもうじき一つになる。","ENG":"Under Mother's care, we will soon become one.","TWN":"在母親的關懷下，我們即將合而為一。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"모두 죽음을 두려워하지 말지어다.","JPN":"皆、死を恐れるな。","ENG":"Fear not death, everyone.","TWN":"大家不要懼怕死亡。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"잠깐, 잠깐!","JPN":"ちょっ、ちょっと！","ENG":"Whoa! Wait!","TWN":"等一下，等一下！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그렇게 갑자기 무턱대고 들이대면……!","JPN":"そうやって、いきなり飛び込んだら……！","ENG":"You all just creeped up on me...!","TWN":"你們這樣突然進攻……！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"나야 완전 땡큐땡큐지~!","JPN":"アタシ大喜びだよ～！","ENG":"But you're all welcome!","TWN":"我當然是很感激了～！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"미안하지만, 돌아가서 맥크레디 양에게 전하게. 리벳.","JPN":"悪いが、戻ってマクレディー君に伝えてくれ。リベット。","ENG":"Rivet, I'm sorry, but go back and tell Ms. MacCready.","TWN":"抱歉，里維，你回去轉告麥克蕾蒂小姐。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"지금 나의 궁금증은…… 학회가 추구해왔던 호수, 그 너머에 있다고 말이야.","JPN":"今の私の気がかりは……学会が追求してきた湖、その向こうにあると。","ENG":"That my curiosity is beyond the Lake that the Society pursued all along.","TWN":"現在我的疑問……就在學會一直追求的湖水彼岸。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};